using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter;

    public StringFormatterTests()
    {
        _formatter = new StringFormatter();
    }

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005559876");

        Assert.StartsWith("(800)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005559876");

        Assert.EndsWith("9876", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_ReturnsDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson");

        Assert.Contains("Anderson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    [DataRow("  Hello World  ", "hello-world")]
    [DataRow("My  First   Post", "my-first-post")]
    [DataRow("Hello!@#World", "hello-world")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post! #1");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("---Hello");

        Assert.StartsWith("h", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithTrailingSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello---");

        Assert.EndsWith("o", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_WholeNumber_ReturnsTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.AreEqual("$42.00", result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_EndsWithCents()
    {
        var result = _formatter.FormatCurrency(10.50m);

        Assert.EndsWith(".50", result);
    }

    [TestMethod]
    public void FormatCurrency_ResultAlwaysHasTwoDecimals_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.5m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(1000.999, "$1001.00")]
    public void FormatCurrency_EdgeCases_ReturnsExpected(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

